import requests
import json
import sys
from requests.auth import HTTPBasicAuth

# Configuration
RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 15672
RABBITMQ_USER = "admin"
RABBITMQ_PASSWORD = "password"
BASE_URL = f"http://{RABBITMQ_HOST}:{RABBITMQ_PORT}/api"

def create_vhost(vhost_name):
    """Create a virtual host"""
    url = f"{BASE_URL}/vhosts/{vhost_name}"
    headers = {'content-type': 'application/json'}
    data = {"tracing": False}
    
    try:
        response = requests.put(url, auth=HTTPBasicAuth(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 201:
            print(f"Created vhost: {vhost_name}")
        elif response.status_code == 204:
            print(f"Vhost already exists: {vhost_name}")
        else:
            print(f"Failed to create vhost {vhost_name}: {response.status_code} - {response.text}")
            return False
        return True
    except Exception as e:
        print(f"Error creating vhost {vhost_name}: {str(e)}")
        return False

def create_user(username, password):
    """Create a user"""
    url = f"{BASE_URL}/users/{username}"
    headers = {'content-type': 'application/json'}
    data = {
        "password": password,
        "tags": ""
    }
    
    try:
        response = requests.put(url, auth=HTTPBasicAuth(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 201:
            print(f"Created user: {username}")
        elif response.status_code == 204:
            print(f"User already exists: {username}")
        else:
            print(f"Failed to create user {username}: {response.status_code} - {response.text}")
            return False
        return True
    except Exception as e:
        print(f"Error creating user {username}: {str(e)}")
        return False

def set_permissions(username, vhost_name, configure, write, read):
    """Set permissions for a user on a vhost"""
    url = f"{BASE_URL}/permissions/{vhost_name}/{username}"
    headers = {'content-type': 'application/json'}
    data = {
        "configure": configure,
        "write": write,
        "read": read
    }
    
    try:
        response = requests.put(url, auth=HTTPBasicAuth(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 204:
            print(f"Set permissions for user {username} on vhost {vhost_name}")
        else:
            print(f"Failed to set permissions for user {username} on vhost {vhost_name}: {response.status_code} - {response.text}")
            return False
        return True
    except Exception as e:
        print(f"Error setting permissions for user {username}: {str(e)}")
        return False

def setup_tenant_environment(tenant_name, user_password):
    """Setup complete tenant environment"""
    # Create vhost for tenant
    vhost_name = f"/tenant-{tenant_name}"
    
    if not create_vhost(vhost_name):
        return False
    
    # Create user for tenant
    username = f"tenant-{tenant_name}"
    if not create_user(username, user_password):
        return False
    
    # Set permissions for tenant user
    configure = ".*"
    write = ".*"
    read = ".*"
    
    if not set_permissions(username, vhost_name, configure, write, read):
        return False
    
    print(f"Tenant {tenant_name} setup complete")
    return True

def main():
    # Example tenant configurations
    tenants = [
        {"name": "app1", "password": "secure_password_1"},
        {"name": "app2", "password": "secure_password_2"},
        {"name": "app3", "password": "secure_password_3"}
    ]
    
    for tenant in tenants:
        setup_tenant_environment(tenant["name"], tenant["password"])

if __name__ == "__main__":
    main()